package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.TreeTypeAdapter;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.lang.reflect.Field;
import java.util.List;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void registerTypeHierarchyAdapter_nullBaseType_throwsNullPointerException() {
    NullPointerException exception = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.registerTypeHierarchyAdapter(null, mock(JsonSerializer.class));
    });
    assertNotNull(exception);
  }

  @Test
  void registerTypeHierarchyAdapter_invalidTypeAdapter_throwsIllegalArgumentException() {
    Object invalidAdapter = new Object();
    IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
      gsonBuilder.registerTypeHierarchyAdapter(String.class, invalidAdapter);
    });
    assertNotNull(exception);
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializer_addsToHierarchyFactories() throws Exception {
    JsonSerializer<Object> serializer = mock(JsonSerializer.class);
    Class<?> baseType = String.class;

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory factoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, serializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, serializer);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      @SuppressWarnings("unchecked")
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);

      assertTrue(hierarchyFactories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonDeserializer_addsToHierarchyFactories() throws Exception {
    JsonDeserializer<Object> deserializer = mock(JsonDeserializer.class);
    Class<?> baseType = Integer.class;

    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory factoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, deserializer))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, deserializer);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      @SuppressWarnings("unchecked")
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);

      assertTrue(hierarchyFactories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withTypeAdapter_addsToFactories() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<String> typeAdapter = mock(TypeAdapter.class);
    Class<String> baseType = String.class;

    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, typeAdapter);
      assertSame(gsonBuilder, returned);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      @SuppressWarnings("unchecked")
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);

      assertTrue(factories.contains(factoryMock));
    }
  }

  @Test
  void registerTypeHierarchyAdapter_withJsonSerializerAndTypeAdapter_addsToBothLists() throws Exception {
    // Create a mock that implements both JsonSerializer and TypeAdapter
    Object adapter = new JsonSerializer<Object>() {
      @Override
      public com.google.gson.JsonElement serialize(Object src, java.lang.reflect.Type typeOfSrc,
          com.google.gson.JsonSerializationContext context) {
        return null;
      }
    };

    @SuppressWarnings("unchecked")
    TypeAdapter<Object> typeAdapter = mock(TypeAdapter.class);

    // Create a proxy object that is both JsonSerializer and TypeAdapter
    Object combinedAdapter = new Object() implements JsonSerializer<Object>, TypeAdapter<Object> {
      @Override
      public com.google.gson.JsonElement serialize(Object src, java.lang.reflect.Type typeOfSrc,
          com.google.gson.JsonSerializationContext context) {
        return null;
      }
    };

    // Since creating such proxy is complicated, we test separately
    // Here test separately by calling registerTypeHierarchyAdapter twice with same baseType and different adapters

    Class<Object> baseType = Object.class;

    // Register JsonSerializer
    try (MockedStatic<TreeTypeAdapter> treeTypeAdapterMockedStatic = Mockito.mockStatic(TreeTypeAdapter.class)) {
      TreeTypeAdapter.TreeTypeAdapterFactory treeFactoryMock = mock(TreeTypeAdapter.TreeTypeAdapterFactory.class);
      treeTypeAdapterMockedStatic.when(() -> TreeTypeAdapter.newTypeHierarchyFactory(baseType, adapter))
          .thenReturn(treeFactoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, adapter);
      assertSame(gsonBuilder, returned);

      Field hierarchyFactoriesField = GsonBuilder.class.getDeclaredField("hierarchyFactories");
      hierarchyFactoriesField.setAccessible(true);
      @SuppressWarnings("unchecked")
      List<TypeAdapterFactory> hierarchyFactories = (List<TypeAdapterFactory>) hierarchyFactoriesField.get(gsonBuilder);

      assertTrue(hierarchyFactories.contains(treeFactoryMock));
    }

    // Register TypeAdapter
    try (MockedStatic<TypeAdapters> typeAdaptersMockedStatic = Mockito.mockStatic(TypeAdapters.class)) {
      TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);
      typeAdaptersMockedStatic.when(() -> TypeAdapters.newTypeHierarchyFactory(baseType, typeAdapter))
          .thenReturn(factoryMock);

      GsonBuilder returned = gsonBuilder.registerTypeHierarchyAdapter(baseType, typeAdapter);
      assertSame(gsonBuilder, returned);

      Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
      factoriesField.setAccessible(true);
      @SuppressWarnings("unchecked")
      List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);

      assertTrue(factories.contains(factoryMock));
    }
  }
}
